<?php
declare(strict_types=1);
require_once __DIR__ . '/_storefront.php';
mg_require_method('GET');$user=mg_require_permission('storefront.preview');$pdo=mg_db();$store=mg_storefront_owned($pdo,(int)$user['id']);if(!$store)mg_fail('Storefront not found.',404);$revision=mg_storefront_revision($pdo,(int)$store['id'],'draft')?:mg_storefront_revision($pdo,(int)$store['id'],'published');if(!$revision)mg_fail('Storefront revision not found.',404);
$products=array_values(array_filter(mg_storefront_revision_products($pdo,(int)$revision['id']),static fn(array $p):bool=>$p['visibility']==='visible'&&$p['status']==='published'));foreach($products as &$product){$product['cover_url']=$product['cover_asset_id']?'/api/public/media.php?asset='.rawurlencode((string)$product['cover_asset_id']):null;$product['product_url']='/product.php?p='.rawurlencode((string)$product['slug']);}
$assetPublic=static function(PDO $pdo,mixed $id):?string{if(!$id)return null;$stmt=$pdo->prepare('SELECT public_id FROM catalog_assets WHERE id=?');$stmt->execute([(int)$id]);$value=$stmt->fetchColumn();return $value?(string)$value:null;};$logo=$assetPublic($pdo,$revision['logo_asset_id']);$cover=$assetPublic($pdo,$revision['cover_asset_id']);
mg_ok(['storefront'=>['slug'=>$store['slug'],'display_name'=>$revision['display_name'],'headline'=>$revision['headline'],'description'=>$revision['description'],'status'=>$revision['revision_status'],'logo_url'=>$logo?'/api/public/media.php?asset='.rawurlencode($logo):null,'cover_url'=>$cover?'/api/public/media.php?asset='.rawurlencode($cover):null,'contact'=>$revision['contact_json']?json_decode((string)$revision['contact_json'],true):[],'theme'=>$revision['theme_json']?json_decode((string)$revision['theme_json'],true):[]],'products'=>$products]);
